import{_ as e,o as a,c as b,j as p,a as t,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const h=JSON.parse('{"title":"2.7.3.生理类本源","description":"","frontmatter":{},"headers":[],"relativePath":"1.基础规则/2.建卡相关/2.7.本源/2.7.3.生理类本源.md","filePath":"1.基础规则/2.建卡相关/2.7.本源/2.7.3.生理类本源.md"}'),s={name:"1.基础规则/2.建卡相关/2.7.本源/2.7.3.生理类本源.md"};function _(d,r,o,l,i,c){return a(),b("div",null,[...r[0]||(r[0]=[p("h1",{id:"_2-7-3-生理类本源",tabindex:"-1"},[t("2.7.3.生理类本源 "),p("a",{class:"header-anchor",href:"#_2-7-3-生理类本源","aria-label":'Permalink to "2.7.3.生理类本源"'},"​")],-1),p("table",{class:"bannerparthead"},[p("tbody",null,[p("tr",{id:"hdr"},[p("td",{class:"runninghead",nowrap:""},"灵魂蓝调012")])])],-1),n('<h1 id="生理类本源" tabindex="-1">生理类本源 <a class="header-anchor" href="#生理类本源" aria-label="Permalink to &quot;生理类本源&quot;">​</a></h1><p>生理类本源</p><p>生理类：</p><p>披荆斩棘（行动系）</p><p>本源主流：</p><p>潜能爆发：在拥有此本源主流后，你无法再主动开锁，失去所有潜在的超凡表现机会，除熟练度、潜能爆发外所有的基因锁检定加值失效。相应的，在每次基因锁检定中，你将额外获得1次重投基因锁的机会，这一效果每轮只会生效一次。<br> 每当你在基因锁检定中开锁失败，就积攒1潜能点，并承受1点永久存在的剧痛点数，在接下来的某次基因锁检定中，可以消耗对应的潜能点获得下列对应效果：<br> 1点：此次基因锁检定结果+1修正<br> 6点：可以重投此次基因锁检定结果，但必须接受后者<br> X-1点：此次基因锁检定获得X点加值，这会突破基因锁检定加值的上限，但开锁效果减损至原本的一半，这次成功的开启基因锁检定并不会提供任何熟练值。<br> （X为当前所需开启基因锁的阶数上限*10-这一阶数基因锁的熟练值 例：玩家死神当前已达到且未开启的最高阶基因锁为二阶基因锁，具有熟练值为3，则其需要支付2*10-3=17点潜能点才能使用此效果）<br> 需要注意的是，在未度过四阶段基因锁心魔前，由于基因锁本身的限制，人物因此获得的基因锁检定加值不能超过20点。<br> 在使用或消耗潜能点后，因此而产生的剧痛点数也会一并消除。<br> 若你拥有的潜能点等于或多于X，则立即死亡，无法以任何形式复活。</p><p>本源支流：</p><p>合金骸骨：战斗轮中每一轮开始时，立刻获得1dr/-和2点仅用于计算贯穿效果的硬度增加在你的基础防御上，那一轮结束时消失。你基础防御所属的防御类型现在由闪避防御转为天生防御。</p><p>终极兵器：拥有非人类血统/改造时才能正常生效，若这项能力为你提供了额外的天生武器，则在使用这项天生武器进行攻击时可以选择减少3点武器伤害，这次攻击具有【毁灭】。</p><p>黑暗之心：当你承受第二档情绪异常相关的异常点时，你可以选择其中至多一半的情绪异常相关异常点，将它们转化为同等持续时间的某种第三档异常点，对这些第三档异常点的恢复方式等同于原第二档情绪异常的异常点的恢复方式。你始终在承受第二档情绪异常的异常点时少承受1点。</p><p>行监坐守：特殊的，这一项本源支流需要6点本源点才能获得。你的视野范围扩大至360°。若你没有在某回合中进行过移动且你在那个回合中使用了格挡，则在该回合结束时将那次格挡视为使用了杂技动作进行的格挡，若那次格挡已经是杂技动作格挡，则额外返还2AP持续到下个你的回合开始前。</p><p>科技蛮族：你可以对科技本质的物品进行敲打以让它在某些时刻发挥更大效力，并用不合常理的方式进行维修。首次选择此本源时从两项能力中选择一项，第二次选择时获得另一项。<br> 1.对科技本质的载具、随从、物品进行修复检定时，你改为使用力量检定进行修复，但只生效二分之一出目。<br> 2.每轮一次，使用科技本质的武器时，你可以通过一个自由动作对它敲打超载，试图让它更好用一些，这会导致这件武器部分结构遭到损坏，不同等级的科技本质武器最多可以被如此使用（D1C2B3A4S5）次（无支线武器无法如此使用），若使用后已达使用上限，则需要对其至少修复（D15C30B45A60S75）点结构值才能恢复使用，在修复前该武器不能够正常进行攻击。如此使用时，使得该武器攻击时加骰等级提升一级（至多为8加骰）；若已具有【8加骰】，则改为获得5DP此次攻击上的器械加值。若回到主神空间时超载所损耗的结构值仍未完全恢复，则自动恢复之。</p><p>心胜于物（直觉系）</p><p>本源主流：</p><p>午夜动物：在获得此本源后，你注射药物、使用药物的动作将下降至花招动作，同时，你的非恢复类药剂（包括恢复能量、血量等）的耐药性将降至最低，除非达到最高药物抗性，否则视为不存在，达到最高等级时才生效。<br> 同时，若你主动使用的药物具有成瘾性或毒性，则你在这些药剂生效期间免疫等同于具有直觉本源支流数量等级的毒素/药物来源负面效果（无支线1D2C3B4A5）。但当你拥有此本源主流时，你无法购买任何药物的无限版本。<br> 战斗场景中，根据同时生效的药物类型触发以下效果，以下效果每个战斗场景中均只能触发一次：<br> 恢复类药剂（包括恢复能量、血量等）；你额外获得1点快速医疗（医疗点24），这些快疗点会持续至任一恢复类药剂达到任意级别药物抗性或药效结束。<br> 防御类药剂（包括提供各种类型的防御或吸收等）：这些药物提供的各种类型防御、吸收及效果中，各类型防御统一转化为无名防御，提供的吸收及效果均基于无名防御。这一效果会持续至任一防御类药剂达到最高药物抗性或药效结束。<br> 攻击类药剂（包括提供各种增强攻击等）：你可以将攻击类药物提供的攻击检定上的加值（若有）中的每2DP转化为1附加成功，最多以此法转化DP/2等同于直觉本源支流数；你也可以将攻击类药物提供的攻击检定上的加值（若有）中的每3DP转化为4某类型破防，最多以此法转化DP/4等同于直觉本源支流数，且与前者共用上限。这一效果会持续至任一攻击类药剂达到最高药物抗性或药效结束。<br> 其他类药剂：首次使用其他类药剂时，获得仅限于这一行动轮使用的1AP。</p><p>本源支流：</p><p>肾上腺素：首次获得时选择一项获得，第二次获得时获得另一项。<br> 1.你当前每承受4点2档异常点数，就可以获得1点攻击检定上的士气加值。<br> 2.你当前每承受4点3档异常点数，就可以获得1点防御上的无名防御。<br> 获得两次此本源后，你额外获得以下效果：<br> “你当前每承受5点第一档异常点数就可以获得1点某豁免检定上的士气加值。”<br> “你在受到攻击时，可以将当前身上所具有的1点第一档异常点转化为1点你正在承受的第二档异常点，每次所转化的异常点数上限不能超过直觉本源支流数。”</p><p>杀戮本能：战斗场景中，当你杀死任一敌人时，杀戮本能将开始生效：当你的完好生命已完全不存在时，你可以通过每轮消耗1意志力令自己不会因为伤势而晕倒；当你不具有任何意志力时，你可以通过每轮对自己造成1点严重伤害的方式令自己不会因为伤势而晕倒。</p><p>野兽直觉：特殊的，这一项本源支流需要6点本源点才能获得。从听觉、嗅觉、触觉中选择一项，你获得一种基于该感官的非线型感知方式，这视为一个C级别自然本质的侦测方式，当你试图追踪被你击伤的敌人时，你获得等同于拥有的直觉本源支流数点追踪检定上的增强加值。</p><p>强运傍身：当你进行机运检定时，额外获得1点检定加值，一场影片限一次，当你的机运检定出目为1时，你可以将结果变为2。</p><p>快速反应：每轮一次，当你将AP转化为迅捷/反射动作时，若这一行动轮中你已经转化过迅捷/反射动作，则你可以额外获得1AP，只能将其转化为花招或反射动作。</p><p>岿然不动（生存系）</p><p>本源主流：</p><p>恶魔形态：在每场影片中，在一场战斗中使用或消耗了至少6点意志时，这一本源主流将开始生效，统计对应项，若满足条件，则始终生效，若不满足，则无效直至满足：<br> 剩余意志力总和尾数为6：当你消耗意志时，若你从本次消耗意志上获得的加值不为6，则提升至6。<br> 战斗轮中某次攻击DP的尾数为6、附加为6：你获得【谐振】，将获得的破防改为每1点破防获得6米移速。<br> 任一项破防常态尾数为6：你可以在每次攻击中将正好6点该项常态尾数为6的破防转换为数种你已经有的破防，总量为6，在转换后被转换而增加的破防尾数必须为6。<br> 在影片中杀死了6个敌人：你获得基于任一快速医疗的医疗点池的36点医疗点。<br> 使用了6项不同的招式：一轮一次，某次攻击中，若你的攻击DP尾数不为6，则增加至尾数为6。<br> 在某次被攻击时，防御总和尾数为6、附加总和为6：你可以在每次攻击中将正好6点该项常态尾数为6的防御转换为数种你已经有的防御，总量为6，在转换后被转换而增加的防御尾数必须为6。</p><p>本源支流：</p><p>御血术：一轮一次，当你首次支付生理类属性的能量时，你可以选择承受不超过你的传奇耐力点不可豁免的严重伤害，代替等量的能量支付。</p><p>无谋冲锋：你不能进行曲线冲锋，但你的冲锋的移动行为结束后，即使对方离开了攻击范围，也可以按照脱离攻击范围一般进行冲锋攻击，你的冲锋攻击获得C级先制效果。</p><p>幽灵铠甲：特殊的，这一项本源支流需要6点本源点才能获得。当你进行格挡时，因格挡上的附加成功而获得的封闭从每1点提供1点封闭改为从每1点附加成功提供1.5封闭（向上取整）。</p><p>无惧疼痛：每轮一次，当你被冲击点数影响时，你可以选择立即使自身承受至多不超过你的传奇耐力点严重伤害，并移除等量的冲击点数，因此而对自身造成伤害的那回合获得1点快速医疗（医疗点12）。</p><p>战斗专注：当你在战斗中维持专注状态（资源内提及了【专注】词条）时这一本源支流将开始生效：每轮一次，当你进行生理类检定时，你获得1dp表现加值；每轮首次使用魔力时能量消耗减少1点（最低降低至1）；全力攻击时少承受1点防御减值。</p><p>举武不倒：当你在战斗中持有具有【格挡】词条的武器进行格挡时，可以花招动作/反射动作将不超过【岿然不动本源支流】点格挡防御以1：2的比率转化为在格挡时生效的强韧与反射豁免上的器械加值，持续一轮。</p><p>斩破命运（综合系）</p><p>本源主流：</p><p>机械降神：每场影片一次，当你首次在致死危机下存活时（这一般意味着你需要首先陷入致死危机，也就意味着在第14步前生效的效果无法触发机械降神），可以选择使机械降神将立即开始生效。<br> 从当前战斗场景轮次开始，每个你的回合结束时，都需要立即从下列的选项中选择一项，不能重复选择，立即使其生效：<br> ①：若你是因基因锁效果而免除了这次致死危机，则你立即获得2点持续一场景的快速医疗（医疗点24）。<br> ②：若你并非因基因锁效果而免除了这次致死危机，则你立即在你的每个回合开始时多获得持续生效轮数*1AP，直至因此额外获得的AP大于等于你的最高传奇属性点+最低传奇属性点为止，不再增加，但仍会持续获得。<br> ③接下来的一轮中，直至你的下个回合开始前，你受到的第一次攻击造成的伤害减半，第二次受到的攻击造成的伤害*1.5倍<br> ④：你将可以同时招架并格挡，每轮一次，你转化的第二个非移动用途且不使用招式的移动动作减少2AP转化。<br> ⑤：这一项必须在其他所有选项选择后选择，免除机械降神带来的死亡效果。<br> 当战斗结束时，你立即死亡，无法在本场影片中复活。<br> 特殊的，这一本源主流需要24本源点。</p><p>本源支流：</p><p>以手拒之：战斗开始时，进行一次纯力量检定，当你在等同于出目的那一轮次进行一次招架时，以手拒之将立即开始生效，仅对于本次招架而言，你额外获得等同于传奇力量点伤害抵消。</p><p>潦草急就：特殊的，这一项本源支流需要6点本源点才能获得。一天一次，你可以选择一次生理类技能检定进行数次重投，每次重投时需承受等同于你的智力/2*重投次数点表现减值，最多重投等同于你的智力次，直至出目比重投前高或出目为0（用尽重投次数直接归零），必须接受重投后的结果。</p><p>他山之石：当你获得了来源不为你提供的攻击、防御、豁免、单项属性、单项技能加值时，你可以返还给来源提供者等量同种加值，各加值合计后不能超过你的生理类传奇属性之和。你可以花招动作切换返还的加值类型（攻击防御等）与数量。在双方都具有他山之石时，不会互相影响，若为你提供加值者也具有他山之石，则你获得的加值变为减值。同一单位至多同时受到3个他山之石的增益效果。</p><p>先见之明：一场景一次，你进行的侦查检定可以将至多等同于你的生理类传奇属性之和*2点洞察防御转换为这次侦查检定上的表现加值。</p><p>操控现实：特殊的，这一项本源支流需要6点本源点才能获得。每轮开始时，你可以选择至多一个场景内的敌人，并预测本轮该角色回合结束时剩余的AP总量，若二者最终结果相等，则你立即获得持续至本轮结束的等量*1.5（向上取整）的闪避防御。</p><p>=================<br> 生理类本源碎片：<br> 每点本源碎片需要花费1点本源点<br> 本源碎片：<br> 1.每购买2次此项就获得1点生理类技能检定上的增强加值<br> 2.获得能为所有快速治疗使用的8点医疗点<br> 3.获得1点强韧豁免与反射豁免内在加值</p><p>=================</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',44)])])}const A=e(s,[["render",_]]);export{h as __pageData,A as default};
